import { escapeHtml } from "./text.js";
// Resolve the translated text for one locale, falling back to the source string.
function targetFor(input, locale, key, source) {
    const text = input.bundle[locale]?.[key];
    return typeof text === "string" && text.length > 0 ? text : source;
}
// Build (source, target) entries for a locale, optionally dropping untranslated.
export function buildResourceEntries(input, locale, includeUntranslated = false) {
    const entries = [];
    for (const { source, key } of input.sources) {
        const translated = input.bundle[locale]?.[key];
        const hasTranslation = typeof translated === "string" && translated.length > 0 && translated !== source;
        if (!hasTranslation && !includeUntranslated)
            continue;
        entries.push({ key, source, target: targetFor(input, locale, key, source) });
    }
    return entries;
}
// ---- .NET .resx (XML) ----------------------------------------------------------
const RESX_HEADER = `<?xml version="1.0" encoding="utf-8"?>
<root>
  <resheader name="resmimetype"><value>text/microsoft-resx</value></resheader>
  <resheader name="version"><value>2.0</value></resheader>
  <resheader name="reader"><value>System.Resources.ResXResourceReader, System.Windows.Forms, Version=4.0.0.0, Culture=neutral, PublicKeyToken=b77a5c561934e089</value></resheader>
  <resheader name="writer"><value>System.Resources.ResXResourceWriter, System.Windows.Forms, Version=4.0.0.0, Culture=neutral, PublicKeyToken=b77a5c561934e089</value></resheader>
`;
export function toResx(entries) {
    const body = entries
        .map(({ source, target, key }) => {
        const name = escapeHtml(source);
        const value = escapeHtml(target);
        return `  <data name="${name}" xml:space="preserve">\n    <value>${value}</value>\n    <comment>${escapeHtml(key)}</comment>\n  </data>`;
    })
        .join("\n");
    return `${RESX_HEADER}${body}${body ? "\n" : ""}</root>\n`;
}
// ---- gettext .po ---------------------------------------------------------------
function poEscape(value) {
    return value
        .replace(/\\/g, "\\\\")
        .replace(/"/g, '\\"')
        .replace(/\n/g, "\\n")
        .replace(/\t/g, "\\t");
}
export function toPo(entries, locale, sourceLocale) {
    const header = [
        `# Translations for ${locale}.`,
        `# Generated by @hedgeling/i18n. Content-keyed: msgid is the ${sourceLocale} source string.`,
        'msgid ""',
        'msgstr ""',
        `"Language: ${locale}\\n"`,
        '"MIME-Version: 1.0\\n"',
        '"Content-Type: text/plain; charset=UTF-8\\n"',
        '"Content-Transfer-Encoding: 8bit\\n"',
        "",
    ].join("\n");
    const body = entries
        .map(({ source, target }) => `msgid "${poEscape(source)}"\nmsgstr "${poEscape(target)}"`)
        .join("\n\n");
    return `${header}\n${body}${body ? "\n" : ""}`;
}
// ---- flat JSON ({ source: target }) --------------------------------------------
export function toJson(entries) {
    const map = {};
    for (const { source, target } of entries)
        map[source] = target;
    return JSON.stringify(map, null, 2) + "\n";
}
// ---- combined CSV (Key + one column per locale; Unity/Godot friendly) ----------
function csvField(value) {
    return `"${value.replace(/"/g, '""')}"`;
}
export function toCsv(input) {
    const header = ["Key", input.sourceLocale, ...input.locales].map(csvField).join(",");
    const rows = input.sources.map(({ source, key }) => {
        const cells = [source, source, ...input.locales.map((locale) => targetFor(input, locale, key, source))];
        return cells.map(csvField).join(",");
    });
    return [header, ...rows].join("\r\n") + "\r\n";
}
// ---- top-level: build every requested file -------------------------------------
export function buildResourceFiles(input, options) {
    const baseName = options.baseName ?? "Resources";
    const includeUntranslated = options.includeUntranslated ?? false;
    const files = [];
    for (const format of options.formats) {
        switch (format) {
            case "resx": {
                // Neutral (source-language) file: every source mapped to itself.
                const neutral = input.sources.map(({ source, key }) => ({ key, source, target: source }));
                files.push({ filename: `${baseName}.resx`, content: toResx(neutral) });
                for (const locale of input.locales) {
                    files.push({
                        filename: `${baseName}.${locale}.resx`,
                        content: toResx(buildResourceEntries(input, locale, includeUntranslated)),
                    });
                }
                break;
            }
            case "po": {
                // .pot template (empty msgstr) + one .po per locale.
                const template = input.sources.map(({ source, key }) => ({ key, source, target: "" }));
                files.push({ filename: `messages.pot`, content: toPo(template, input.sourceLocale, input.sourceLocale) });
                for (const locale of input.locales) {
                    files.push({
                        filename: `${locale}.po`,
                        content: toPo(buildResourceEntries(input, locale, includeUntranslated), locale, input.sourceLocale),
                    });
                }
                break;
            }
            case "json": {
                for (const locale of input.locales) {
                    files.push({
                        filename: `${locale}.json`,
                        content: toJson(buildResourceEntries(input, locale, includeUntranslated)),
                    });
                }
                break;
            }
            case "csv": {
                files.push({ filename: `strings.csv`, content: toCsv(input) });
                break;
            }
        }
    }
    return files;
}
